// ── Apply updates ─────────────────────────────────────────────────────────

const update = db.prepare(`
  UPDATE module_quiz_questions
  SET question_text=?, choice_a=?, choice_b=?, choice_c=?, correct_choice=?, explanation=?
  WHERE id=?
`);

let updated = 0;
let skipped = 0;

for (const q of questions) {
  const existing = db.prepare("SELECT id FROM module_quiz_questions WHERE id=?").get(q.id);
  if (!existing) { skipped++; continue; }
  update.run(q.question_text, q.choice_a, q.choice_b, q.choice_c, q.correct_choice, q.explanation, q.id);
  updated++;
}

console.log(`Updated: ${updated} questions`);
console.log(`Skipped (not found): ${skipped}`);

// ── Verify answer distribution ────────────────────────────────────────────

console.log("\nVerifying answer distribution...");
const dist = db.prepare(`
  SELECT correct_choice, COUNT(*) as c
  FROM module_quiz_questions
  GROUP BY correct_choice
  ORDER BY correct_choice
`).all();

dist.forEach(r => console.log(`  ${r.correct_choice}: ${r.c} questions`));

// ── Verify no answer is always the longest ────────────────────────────────

console.log("\nChecking if correct answer is longest (should be near 33%)...");
const all = db.prepare("SELECT choice_a, choice_b, choice_c, correct_choice FROM module_quiz_questions").all();
let correctIsLongest = 0;
for (const q of all) {
  const lengths = { A: q.choice_a.length, B: q.choice_b.length, C: q.choice_c.length };
  const longest = Object.entries(lengths).sort((a,b) => b[1]-a[1])[0][0];
  if (longest === q.correct_choice) correctIsLongest++;
}
console.log(`  Correct answer is longest: ${correctIsLongest}/${all.length} (${Math.round(correctIsLongest/all.length*100)}%) — target is ~33%`);
console.log("\nDone.");
